 namespace Pmpr\Common\Foundation\ORM\DB\Traits; use Pmpr\Common\Foundation\ORM\DB\Field as Fields; trait FieldTrait { public function getEnumField(string $qHABt, array $RjnHS) : Fields\Enumeration { return new Fields\Enumeration($qHABt, $RjnHS); } public function getJsonField(string $qHABt) : Fields\Json { return new Fields\Json($qHABt); } public function getTextField(string $qHABt) : Fields\Text { return new Fields\Text($qHABt); } public function getFileField(string $qHABt) : Fields\File { return new Fields\File($qHABt); } public function getStringField(string $qHABt) : Fields\Str { return new Fields\Str($qHABt); } public function getIntegerField(string $qHABt) : Fields\Integer { return new Fields\Integer($qHABt); } public function getForeignField(string $qHABt) : Fields\Foreign { return new Fields\Foreign($qHABt); } public function getBooleanField(string $qHABt) : Fields\Boolean { return new Fields\Boolean($qHABt); } public function getBigIntField(string $qHABt) : Fields\BigInteger { return new Fields\BigInteger($qHABt); } public function getDateTimeField(string $qHABt) : Fields\DateTime { return new Fields\DateTime($qHABt); } public function getTimestampField(string $qHABt) : Fields\Timestamp { return new Fields\Timestamp($qHABt); } public function getTinyIntegerField(string $qHABt) : Fields\TinyInteger { return new Fields\TinyInteger($qHABt); } }
